class Solution:
    def isPossible(self, nums: List[int]) -> bool:
        seqs = []
        for num in nums:
            found = False
            for seq in seqs:
                if num - 1 == seq[-1]:
                    seq.append(num)
                    found = True
                    break
            if not found:
                seqs.append([num])
        return all(len(seq) >= 3 for seq in seqs)
```
